INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Unlimited Invoicing$q$, $q$Create and send unlimited professional invoices and estimates, with recurring billing and automated payment reminders.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Online Payments$q$, $q$Accept credit card and bank transfer (ACH/EFT) payments directly on invoices via Wave Payments.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Double-Entry Bookkeeping$q$, $q$Free built-in accounting engine with a chart of accounts and standard financial statements.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Receipt Scanning$q$, $q$Capture and digitize receipts via the mobile app for automatic expense tracking, unlimited on the Pro plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Bank Connections$q$, $q$Automatically import and categorize transactions from connected bank and credit card accounts via Plaid (Pro plan).$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Payroll$q$, $q$Optional add-on for running payroll, direct deposit, and tax filings in supported US states and Canadian provinces.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Financial Reporting$q$, $q$Generate profit and loss, balance sheet, and cash flow reports for tax time and decision-making.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Mobile Apps$q$, $q$iOS and Android apps for invoicing, receipt capture, and checking cash flow on the go.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Wave Advisors$q$, $q$Access to bookkeeping and tax support from Wave's in-house accounting professionals.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Multi-User Collaboration$q$, $q$Invite unlimited collaborators, such as bookkeepers or business partners, to access the account (Pro plan).$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Core accounting and invoicing tools are free with no user limits$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Simple, intuitive interface that doesn't require accounting expertise$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Built-in payment processing lets clients pay invoices instantly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Mobile apps make invoicing and receipt capture easy on the go$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Optional payroll and bookkeeping add-ons let the platform grow with the business$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Limited third-party integrations compared to competitors like QuickBooks or Xero$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$No inventory management, project tracking, or job costing features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Bank feed automation and unlimited receipt scanning require the paid Pro plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Full-service payroll tax filing is only available in select US states and Canadian provinces$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Live chat and priority support are limited to Pro subscribers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Is Wave really free?$q$, $q$Yes, Wave's Starter plan includes unlimited invoicing, estimates, and basic bookkeeping at no cost; Wave charges for optional services like payment processing fees, the Pro plan, payroll, and bookkeeping support.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$How much does Wave Pro cost?$q$, $q$Wave Pro costs $19 per month, or $190 per year, in the US, and adds automated bank feeds, unlimited receipt scanning, and unlimited collaborators to the free Starter plan.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Does Wave offer payroll?$q$, $q$Yes, Wave Payroll is an optional add-on starting from around $25 per month, with full-service tax filing available only in certain US states and Canadian provinces; self-service payroll is available elsewhere.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$What payment processing fees does Wave charge?$q$, $q$Wave charges 2.9% plus $0.60 per credit card transaction on the free Starter plan, with a reduced rate for the first 10 transactions each month on Pro; bank transfer (ACH/EFT) rates are lower.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Is Wave available outside the US and Canada?$q$, $q$Wave's invoicing and bookkeeping tools can be used by businesses in many countries, but payment processing and payroll features are limited primarily to US and Canadian businesses.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Freelance Invoicing and Payments$q$, $q$Send professional invoices and estimates and let clients pay instantly by card or bank transfer, with automatic reconciliation.$q$, $q$Freelancers and independent contractors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Small Business Bookkeeping$q$, $q$Track income and expenses, connect bank accounts, and generate the financial reports needed at tax time.$q$, $q$Solo-operator small businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Service Business Client Billing$q$, $q$Set up recurring billing and automated late-payment reminders for ongoing client relationships.$q$, $q$Consultants and small agencies$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Adding Payroll as a Team Grows$q$, $q$Layer on the payroll add-on for direct deposit and tax filings once a business starts hiring employees or contractors.$q$, $q$Small businesses with a few employees or contractors$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Starter$q$, $q$$0$q$, $q$Free$q$, $q$["Unlimited invoices and estimates","Basic double-entry bookkeeping","Online payments at standard processing rates","Mobile app access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Pro$q$, $q$$19/month or $190/year$q$, $q$Monthly or annual$q$, $q$["Everything in Starter","Automated bank and credit card feeds via Plaid","Unlimited receipt scanning","Discounted payment processing on first 10 transactions/month","Unlimited collaborators","Automated late payment reminders"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$Payroll Add-on$q$, $q$From $25/month$q$, $q$Monthly$q$, $q$["Employee and contractor direct deposit","Full-service tax filing in supported US states and Canadian provinces","Self-service payroll elsewhere"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Wave is a cloud-based accounting, invoicing, and financial software platform built for small business owners, freelancers, and self-employed professionals. Founded in Toronto in 2009 by Kirk Simpson and James Lochrie, Wave set out to give the smallest businesses free access to tools that had traditionally been priced for larger companies. In 2019, the company was acquired by H&R Block, which continues to operate Wave as a standalone brand focused on small business financial software.$q$, $q$At its core, Wave offers free double-entry accounting, unlimited invoicing and estimates, and basic bookkeeping tools, all accessible through a web browser with companion mobile apps for iOS and Android. Revenue comes from optional paid services layered on top of the free product: a Pro subscription that unlocks bank-feed automation and receipt scanning, plus add-ons for online payment processing, payroll, and professional bookkeeping support delivered by Wave's in-house accountants.$q$, $q$This freemium structure has made Wave one of the most widely used accounting tools among microbusinesses and solo entrepreneurs who need to look professional and stay organized without committing to a monthly software budget. It trades some of the depth, integrations, and industry-specific functionality of larger platforms like QuickBooks or Xero for simplicity and cost, which is precisely the tradeoff its target audience is looking for.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$who-wave-is-for$q$, $q$Who Wave Is For$q$, 2, ARRAY[$q$Wave is best suited to freelancers, consultants, and solo service providers who need to send professional invoices, accept payments, and track income and expenses without paying for accounting software. Its free tier covers the essentials most one-person businesses need: unlimited invoices, basic bookkeeping, and simple financial statements, making it an easy entry point for anyone just starting to formalize their finances.$q$, $q$It also works well for small product or service businesses with a handful of transactions per month, where Wave's bank-connection and receipt-scanning tools, available on the Pro plan, can meaningfully cut down on manual data entry. Businesses that primarily invoice clients and get paid by card or bank transfer benefit from Wave's built-in payment processing, which deposits funds directly and reconciles automatically against invoices.$q$, $q$Wave also appeals to budget-conscious founders and side-hustlers who want a single dashboard for cash flow, customers, and taxes without hiring a bookkeeper right away, and who may later add Wave's payroll or bookkeeping-support add-ons as their business grows rather than switching platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Wave is not the right fit for growing companies that need inventory management, project or time tracking, multi-currency accounting at scale, or detailed job costing, since these are outside its feature set. Businesses with more than a few employees, complex approval workflows, or a need for granular user permissions will also find Wave's simpler, largely single-user-oriented design limiting.$q$, $q$Companies that rely heavily on third-party integrations, such as e-commerce platforms, inventory systems, or CRM tools, may be frustrated by Wave's comparatively small app ecosystem next to competitors like QuickBooks Online or Xero. Wave's payroll add-on also covers a limited number of US states and Canadian provinces for full-service tax filing, so employers outside that coverage area, or with more complex payroll needs, should confirm availability before relying on it.$q$, $q$Businesses that expect fast, dedicated customer support at every tier may also be disappointed, since live chat and priority support are reserved for the Pro plan, and some users report slower response times on the free plan. Larger or multi-entity businesses are generally better served by a more scalable platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Wave's core feature set centers on unlimited, customizable invoicing and estimates, with automatic payment reminders, recurring billing, and a Pay Now button that lets clients pay directly from an invoice by card or bank transfer. Behind the scenes, Wave provides free double-entry bookkeeping, a chart of accounts, and standard financial reports such as profit and loss, balance sheet, and cash flow statements.$q$, $q$Paid add-ons extend the platform: Wave Payments processes credit card and ACH/EFT transactions at competitive per-transaction rates, Wave Payroll handles employee and contractor pay with direct deposit and tax filings in supported regions, and Wave Advisors connects users with bookkeepers and accountants for hands-on support or year-end tax preparation.$q$, $q$The Pro plan adds automated bank and credit card feeds via Plaid, automatic transaction categorization and merging, unlimited receipt scanning through the mobile app, and unlimited collaborator seats, while mobile apps for iOS and Android let users invoice, capture receipts, and check cash flow on the go.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', $q$the-wave-experience$q$, $q$The Wave Experience$q$, 2, ARRAY[$q$Users consistently point to Wave's clean, uncluttered interface as one of its biggest strengths, especially compared to more feature-dense competitors that can overwhelm non-accountants. Setup is fast: most small business owners can create an account, add their business details, and send their first invoice within minutes, with little to no accounting background required.$q$, $q$Reviews on sites like Capterra and G2 frequently praise Wave's free plan for how much value it offers, though some users note occasional syncing issues with bank feeds and want faster, more consistent customer support outside the Pro tier. Overall satisfaction tends to be highest among freelancers and very small businesses whose needs align closely with what Wave was built to do.$q$, $q$Because Wave is entirely cloud-based, updates roll out automatically and data stays accessible from any device with a browser, without the maintenance overhead of desktop accounting software. For businesses that outgrow it, migrating financial data to a more robust platform is a common next step, but many users report staying with Wave far longer than expected simply because it continues to meet their needs affordably.$q$]::text[], 4);
