INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e5e2d12b-a101-4a07-8262-007ffad934e6', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Drag-and-drop editor$q$, $q$A visual, WYSIWYG editor lets users place text, images, buttons, and forms anywhere on a page without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Free responsive templates$q$, $q$A library of mobile-responsive themes is included at no extra cost on every plan, though the selection is updated infrequently.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Built-in online store$q$, $q$Native e-commerce tools cover product listings, inventory tracking, coupons, digital goods, and shipping calculators for small catalogs.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Square payments integration$q$, $q$Checkout and card processing run through Square, letting merchants who already use Square in-store unify online and offline sales reporting.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$App Center integrations$q$, $q$A marketplace of third-party apps adds functionality such as email marketing, live chat, and reviews that isn't built into the core editor.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Basic SEO tools$q$, $q$Editable meta titles, descriptions, custom URLs, and an auto-generated sitemap give small sites the essentials for search visibility.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Mobile apps for iOS and Android$q$, $q$Native apps let site owners edit content, check site stats, and respond to contact-form leads directly from a phone or tablet.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Blogging platform$q$, $q$An integrated blog module supports posts, categories, and comments alongside the main website without extra plugins.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Membership and password protection$q$, $q$Higher-tier plans support member areas and password-protected pages for gated or subscriber-only content.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Site statistics and analytics$q$, $q$Built-in stats show visitor traffic, popular pages, and store performance directly inside the Weebly dashboard.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Free plan and low-cost paid tiers make it one of the more affordable full-featured site builders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Drag-and-drop editor is genuinely beginner-friendly with a short learning curve$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Built-in e-commerce, blogging, and marketing tools are bundled into a single editor$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Square payment integration is convenient for merchants who already use Square in-store$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Mobile apps let owners manage a site and respond to leads away from a desktop$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Template library is smaller and less frequently refreshed than rival builders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Switching templates after launch generally requires rebuilding site content$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$E-commerce features are lighter than dedicated platforms for larger or complex catalogs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Faster support (phone, priority response) is limited to higher-priced plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Payment processing is tied to Square, which limits flexibility for merchants preferring another processor$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Is Weebly free to use?$q$, $q$Yes, Weebly offers a permanent free plan that includes unlimited pages, free SSL, and basic e-commerce, though it displays Weebly/Square branding and lacks features reserved for paid tiers.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Does Weebly charge transaction fees on online store sales?$q$, $q$Weebly's Free, Personal, and Professional plans apply a platform transaction fee on top of standard payment processing costs; the higher-tier Performance plan removes that platform fee.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Can I connect a custom domain to my Weebly site?$q$, $q$Yes, custom domain connection is available starting on the Personal plan, and paid annual plans typically include a free domain for the first year.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Is Weebly good for SEO?$q$, $q$Weebly covers core on-page SEO needs, such as editable meta titles, descriptions, and sitemaps, but offers fewer advanced technical SEO controls than platforms built specifically around content or commerce.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Who owns Weebly?$q$, $q$Weebly was acquired by Square (now Block, Inc.) in 2018 and operates as part of Square's broader commerce and payments product suite.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Launching a small business website quickly$q$, $q$A local service business can build a brochure-style site with contact details, service pages, and a booking or contact form in a single afternoon.$q$, $q$Small business owners and local entrepreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Selling a modest product catalog online$q$, $q$A merchant already using Square in-store can add an online store that shares payment processing and reporting with their physical location.$q$, $q$Solo merchants and small retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Publishing a portfolio or blog$q$, $q$Freelancers and creatives can showcase work and publish regular posts using Weebly's built-in blog and gallery modules.$q$, $q$Freelancers, artists, and independent writers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Building a low-cost site for a nonprofit or community group$q$, $q$Organizations with limited budgets and simple content needs can maintain an informational site without hiring a developer.$q$, $q$Nonprofits and community organizations$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, $q$["Unlimited pages","Free SSL security","Basic e-commerce with platform transaction fee","Weebly/Square branding","Community forum support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Personal$q$, $q$From $10/month (billed annually); higher month-to-month$q$, $q$Annual or monthly$q$, $q$["Custom domain connection","Unlimited storage","Advanced site statistics","Video backgrounds"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Professional$q$, $q$From $12/month (billed annually); higher month-to-month$q$, $q$Annual or monthly$q$, $q$["Free domain for first year","Remove Square/Weebly branding","Password-protected pages","Site search","Member areas"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Performance$q$, $q$From $26/month (billed annually); higher month-to-month$q$, $q$Annual or monthly$q$, $q$["No platform transaction fee","Abandoned cart emails","Shipping label printing","Advanced e-commerce insights","Priority phone support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Weebly is a website-building platform founded in 2007 by David Rusenko, Chris Fanini, and Dan Veltri with the goal of letting anyone publish a website without writing code. In 2018, Square (now Block, Inc.) acquired Weebly for roughly $365 million, folding its drag-and-drop editor into Square's broader commerce ecosystem alongside its point-of-sale and payments tools.$q$, $q$Today Weebly functions as a straightforward, what-you-see-is-what-you-get site builder: users drag elements such as text blocks, images, contact forms, and buttons onto a page and publish instantly, either on a free weebly.com subdomain or a connected custom domain. It bundles a lightweight online store, a blogging engine, and a handful of marketing add-ons into the same editor, so a single subscription can cover a brochure site, a blog, and a basic shop.$q$, $q$Because it now sits inside Square's product family, Weebly's checkout and card processing run on Square's payment rails, which is convenient for merchants who already use Square in a physical store but a factor to weigh for anyone who wants a different payment processor. The platform still targets the audience it always has: individuals and small businesses that want an inexpensive site up quickly rather than a highly customized, developer-built one.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$who-weebly-is-for$q$, $q$Who Weebly Is For$q$, 2, ARRAY[$q$Weebly suits solo founders, freelancers, and very small teams who need a functional website in an afternoon rather than a design system built over weeks. Its free plan and low entry-level pricing make it a reasonable starting point for hobby projects, portfolios, and local service businesses that mainly need a digital business card with contact details, hours, and a few photos.$q$, $q$It also works well for small merchants who already process payments through Square in-store and want their online store's transactions to reconcile with the same dashboard and reporting used for their physical location. Because Weebly's e-commerce tools cover the basics, such as product listings, inventory tracking, coupons, and shipping calculators, a shop owner selling a modest catalog can get online without learning a more complex platform.$q$, $q$Bloggers, community organizations, churches, and nonprofits with straightforward content needs are another good fit, since Weebly's built-in blog, simple SEO controls, and free template library handle typical use cases without requiring plugins, custom code, or a developer on retainer.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses that expect to scale into a large product catalog, multi-currency selling, or complex checkout logic will likely outgrow Weebly's e-commerce tools, which are noticeably lighter than dedicated platforms built specifically for online retail.$q$, $q$Designers and developers who want granular control over layout, custom code injection, or a large, frequently refreshed template library may find Weebly's editor and theme selection dated compared to newer builders; templates also cannot be swapped after a site is built without largely rebuilding its content and layout.$q$, $q$Merchants who don't want to route payments through Square, or teams that need advanced marketing automation, multi-language content management, or headless and API-first flexibility, should also look elsewhere, since Weebly is optimized for simplicity and speed rather than depth or extensibility.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Weebly offers a drag-and-drop editor paired with a library of free, mobile-responsive templates, plus native modules for a blog, contact forms, image galleries, and an online store with inventory management, discount codes, and Square-powered checkout.$q$, $q$Paid plans add custom domain connection, site search, password-protected pages and member areas, video backgrounds, and mobile apps for iOS and Android that let owners edit a site, check statistics, and respond to contact-form leads on the go. An App Center supplies additional third-party integrations, such as email marketing, live chat, and review widgets, for functionality not built natively into the core editor.$q$, $q$SEO tooling covers the fundamentals: editable meta titles and descriptions, custom page URLs, an auto-generated sitemap, and basic site analytics, giving small sites the essentials for search visibility without the deeper technical SEO controls found in more specialized content or commerce platforms.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$the-weebly-experience$q$, $q$The Weebly Experience$q$, 2, ARRAY[$q$New users typically describe Weebly's editor as one of the more approachable options in the website-builder category: elements snap into place with minimal fiddling, and a working page can be live within an hour of signing up. That simplicity is also its biggest trade-off, since deep customization, such as pixel-level control or extensive custom code sections, is more limited than on code-friendlier builders.$q$, $q$Reviewers consistently note that Weebly's template library, while free across every plan, has not been refreshed as often as competitors', giving many sites a similar, somewhat dated look unless customized further with additional CSS. Editor performance can also feel sluggish on larger, image-heavy pages, and switching templates after launch typically means rebuilding much of the site.$q$, $q$Support quality varies by plan: free and entry-level users get email and chatbot help, while phone support and faster response times are reserved for the higher-tier Performance plan. Overall, the experience rewards users who want a fast, low-maintenance site over those chasing a highly bespoke design or complex functionality.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
