INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Large File Transfers$q$, $q$Send files without an email attachment limit; recipients download directly from a link without needing a WeTransfer account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Password Protection$q$, $q$Add a password to a transfer so only people with the code can open and download the files.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Custom Link Expiration$q$, $q$Control how long a download link stays active, from a short default window on free accounts to longer custom periods on paid plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Transfer Tracking$q$, $q$See when a transfer has been opened or downloaded so you know a delivery has been received.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Branded Transfer Pages$q$, $q$Apply your own branding to the page recipients see when downloading files, available on paid tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$File Requests$q$, $q$Generate a link that lets other people upload files directly to you, useful for collecting assets or submissions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Collect Moodboards$q$, $q$Save and organize images and inspiration into shareable visual boards through WeTransfer's Collect tool.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Mobile and Mac Apps$q$, $q$Native iOS and Android apps plus a Mac menu-bar app let you send files without opening a browser.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Cloud Storage$q$, $q$Paid plans include cloud storage for keeping and sharing files beyond a single one-off transfer.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Encrypted Transfers$q$, $q$Files are encrypted in transit and at rest while stored on WeTransfer's servers before download.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Very simple, no-signup interface that lets recipients download without creating an account$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Free tier covers occasional large-file sending without hitting typical email attachment limits$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Distinctive, artist-designed visual experience that stands out from generic file-sharing tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Paid plans scale reasonably from solo freelancers up to small collaborating teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Native iOS, Android, and Mac apps make sending files convenient outside the browser$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Free plan's transfer and volume limits are easy for regular users to exceed$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Files and links expire by design, so it isn't suited to long-term storage or archiving$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Public developer API has been retired, limiting automation and custom integrations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Fewer collaboration and permission controls than full cloud-storage suites like Google Drive or Dropbox$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Major layoffs following the 2024 Bending Spoons acquisition raise questions about long-term support pace$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Is WeTransfer free to use?$q$, $q$Yes. The free plan allows a limited number of transfers and total data within a rolling 30-day period, with no account required for recipients to download.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$How long do WeTransfer download links stay active?$q$, $q$On the free plan, links typically stay active for a few days; paid plans allow custom expiration windows that can be extended further.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Is WeTransfer secure?$q$, $q$WeTransfer encrypts files in transit and at rest, and paid features like password protection and access controls add further security to transfers.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Do recipients need a WeTransfer account to download files?$q$, $q$No. Recipients simply click the link they receive by email or that you share directly, then download the files without signing up.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$What happened to WeTransfer's old Pro and Premium plans?$q$, $q$Following its 2024 acquisition by Bending Spoons, WeTransfer restructured its paid plans into Starter, Ultimate, and Teams tiers, replacing the older Pro and Premium naming.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Delivering finished creative work to clients$q$, $q$Photographers, videographers, and designers send finished project files, like high-resolution images or video masters, directly to clients through a simple branded link.$q$, $q$Freelance creatives and agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Sending large media files to remote collaborators$q$, $q$Production teams move raw footage, project files, or design assets between distributed team members without email size limits.$q$, $q$Remote teams and production crews$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Collecting files from external contributors$q$, $q$Teams use file request links to gather submissions, assets, or documents from clients, candidates, or vendors without granting them account access.$q$, $q$Marketing, HR, and operations teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$One-off personal file sharing$q$, $q$Individuals send large personal files, such as event photos or home videos, to family and friends without setting up a cloud-storage account.$q$, $q$Individuals and casual senders$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Up to 10 transfers or 3GB total every 30 days","Password-protected transfers","File requests","Transfer overview and download notifications","Links stay active for a few days"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Starter$q$, $q$$6.99$q$, $q$Monthly$q$, $q$["Up to 10 transfers or 300GB total every 30 days","Password protection","Longer link expiration","Ad-free experience"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Ultimate$q$, $q$$25$q$, $q$Monthly$q$, $q$["Unlimited transfers up to 1TB per transfer","Custom link expiration","Password protection","Branded transfer pages","Access control for recipients","Cloud storage included"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Teams$q$, $q$Custom$q$, $q$Contact sales$q$, $q$["Everything in Ultimate","Shared team workspace","Team branding controls","Admin and usage controls","Expanded shared storage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$WeTransfer is a Dutch file-transfer and sharing service founded in 2009 in Amsterdam. It built its reputation on a simple promise: let anyone send a large file to anyone else through a plain web link, without accounts, installs, or complicated settings getting in the way. That simplicity, paired with a distinctive full-screen artwork backdrop commissioned from artists and photographers, turned a basic utility into one of the more recognizable tools among creative professionals.$q$, $q$The core product remains a browser-based upload flow: drag files in, add an email or generate a link, and the recipient downloads directly, no sign-in required on their end. A free tier covers occasional, lower-volume sending, while paid plans raise transfer size and frequency limits, add password protection and custom expiration, and layer on cloud storage and branding options aimed at freelancers, agencies, and small teams.$q$, $q$WeTransfer was acquired by Bending Spoons in 2024, which was followed by a significant reduction in staff and a restructuring of the product lineup into Free, Starter, Ultimate, and Teams plans. The company has also folded in adjacent creative tools, such as its Collect moodboard app, positioning WeTransfer less as a one-off utility and more as a lightweight suite for people who move creative files for a living.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$who-wetransfer-is-for$q$, $q$Who WeTransfer Is For$q$, 2, ARRAY[$q$Freelance photographers, videographers, designers, and other creatives who regularly need to deliver finished assets to clients are the clearest fit. Large image sets, video masters, and design files routinely exceed email attachment limits, and WeTransfer's link-based delivery avoids the friction of asking a client to create an account on a shared drive.$q$, $q$Small agencies and production teams that want a quick, branded way to hand off deliverables also benefit, since paid plans allow custom expiration windows, password protection, and a branded transfer page that looks more polished than a generic download link.$q$, $q$Casual, occasional senders are well served too. Anyone who needs to move a single large file, like wedding photos or a home video, without setting up a full cloud-storage account, can do so on the free tier in a couple of clicks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations that need granular permissions, long-term document storage, or deep collaboration features, such as simultaneous editing, version history, or folder-level access control, are generally better served by a full cloud-storage suite like Google Drive, Dropbox, or OneDrive, which WeTransfer was never designed to replace.$q$, $q$Teams looking to automate file delivery through a developer integration should also look elsewhere for now, since WeTransfer's public developer API has been retired and is no longer officially supported, leaving only unmaintained community wrappers.$q$, $q$Anyone who needs guaranteed permanent storage or archival should avoid relying on WeTransfer transfers for that purpose, since links expire by design; the free and Starter tiers in particular are built around short-lived links rather than durable storage.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, WeTransfer offers straightforward large-file sending: recipients don't need an account to download, and senders can attach a password and set an expiration window on higher plans. Paid tiers raise both the per-transfer size ceiling and the number of transfers allowed within a rolling 30-day period.$q$, $q$Beyond basic sending, the product includes file requests for collecting uploads from other people, transfer tracking so senders can see when a file has been opened, and branded transfer pages that let paying users apply their own look to the download experience their clients see.$q$, $q$WeTransfer also ships native apps, including iOS and Android mobile apps and a Mac menu-bar app, plus its Collect tool for building visual moodboards. Higher-tier plans add cloud storage for files beyond a single transfer, along with team workspaces and administrative controls on the Teams plan.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$the-wetransfer-experience$q$, $q$The WeTransfer Experience$q$, 2, ARRAY[$q$Using WeTransfer feels deliberately uncomplicated. The upload screen is dominated by rotating, full-bleed artwork from partnered artists rather than dense menus, and sending a file is typically a three-step process: add files, add an email or generate a link, and hit send.$q$, $q$That minimalism is both the appeal and the limitation. There is little in the way of collaborative editing, nested folder structures, or fine-grained sharing permissions, so the experience is optimized for one-directional handoff rather than ongoing teamwork inside shared files.$q$, $q$For the audience it targets, mostly individuals and small teams who need to move big files quickly and want the process to feel a bit more considered than a generic upload form, that trade-off tends to work in its favor, even if larger organizations may find the feature set thinner than dedicated cloud-storage platforms.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
