INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Drag-and-Drop Scheduling$q$, $q$Build, edit, and publish weekly or multi-week schedules quickly using a visual drag-and-drop grid and reusable shift templates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Auto-Scheduler$q$, $q$Automatically matches open shifts to employees based on their availability, eligibility, and stated shift preferences.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$GPS Time Clock & Geofencing$q$, $q$Employees clock in and out from their phone or a shared kiosk, with GPS capture and geofencing to confirm on-site punches.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Shift Swapping & Open Shifts$q$, $q$Staff can request swaps, drop shifts, or claim open shifts themselves, with manager approval rules applied automatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Team Messaging$q$, $q$Built-in one-to-one and group messaging, plus shift reminders and announcements, delivered through the same scheduling app.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Time-Off & Availability Management$q$, $q$Employees submit availability and time-off requests that managers can review and approve directly within the schedule.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Labor Forecasting & Reporting$q$, $q$Pro and Premium plans add labor cost forecasting, custom reports, and 24-hour callout reporting for tighter budget control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Payroll Integrations$q$, $q$Native integrations with providers such as Gusto, QuickBooks Online, ADP Workforce Now, and Square Payroll streamline payroll runs.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Mobile Apps for iOS & Android$q$, $q$Full-featured native apps let employees and managers handle scheduling, time tracking, and messaging from anywhere.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$API, Webhooks & SSO$q$, $q$The Premium plan adds API key access, webhooks, and SAML/SSO for organizations that need deeper system integration.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Fast, intuitive drag-and-drop schedule building that most managers pick up quickly$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Employees can self-serve shift swaps, drops, and open-shift claims within manager-set rules$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$GPS-verified time clock ties directly into several native payroll integrations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Team messaging, reminders, and schedule access are combined in one mobile app$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Transparent per-user monthly pricing with no long-term contract and easy plan changes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$The mobile app does not fully work offline, which is a problem for job sites with poor connectivity$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Some users report bugs, crashes, and syncing delays on both web and mobile$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Advanced features like forecasting, custom permissions, and SSO are gated behind higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Time Clock & Attendance is a separate paid add-on and its pricing is not published upfront$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Best suited to hourly, shift-based work, so salaried or fixed-schedule teams get less value$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Does When I Work have a free plan?$q$, $q$There is no permanent free plan. When I Work offers a 14-day free trial with full feature access and no credit card required, after which you choose a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$How much does When I Work cost?$q$, $q$Paid plans are billed per user per month: Essentials at $2.50, Pro at $5, and Premium at $8. Time Clock & Attendance is an optional add-on with pricing available on request, and custom enterprise pricing is also available.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Does When I Work integrate with payroll software?$q$, $q$Yes. With the Time Clock & Attendance add-on enabled, When I Work integrates natively with providers including Gusto, QuickBooks Online, ADP Workforce Now, and Square Payroll.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Is there a When I Work mobile app?$q$, $q$Yes, When I Work has native iOS and Android apps that let employees view schedules, clock in and out, message coworkers, and request time off or shift swaps.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$What types of businesses use When I Work?$q$, $q$It is designed for shift-based, hourly workforces such as restaurants, retail stores, hospitality, healthcare, gyms, and other service businesses with rotating schedules.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Restaurant and hospitality shift scheduling$q$, $q$Restaurant, cafe, and hotel managers use When I Work to build weekly shift schedules, fill last-minute open shifts, and communicate changes instantly to front- and back-of-house staff.$q$, $q$Restaurant and hospitality managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Multi-location retail workforce management$q$, $q$Retail chains use labor sharing, forecasting, and custom reporting on the Pro and Premium tiers to give regional managers visibility across several store locations from one account.$q$, $q$Multi-location retail and franchise operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Healthcare and home-care staff scheduling$q$, $q$Clinics, home-care agencies, and other healthcare providers use GPS-verified time tracking and shift scheduling to confirm caregiver attendance and simplify payroll for hourly staff.$q$, $q$Healthcare and home-care administrators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Replacing spreadsheet-based scheduling$q$, $q$Small business owners moving off spreadsheets or paper schedules use the Essentials plan to publish schedules, track time, and message staff without hiring dedicated scheduling admin support.$q$, $q$Small business owners and first-time schedulers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Essentials$q$, $q$$2.50 per user$q$, $q$Monthly$q$, $q$["Single location or schedule","Drag-and-drop scheduling and templates","Auto-scheduler and open shifts","Team messaging and shift reminders","Time-off and availability requests"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Pro$q$, $q$$5 per user$q$, $q$Monthly$q$, $q$["Multiple locations or schedules","Everything in Essentials","Labor sharing across locations","Forecasting and custom reporting","Role-based permissions and 24-hour callout reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Premium$q$, $q$$8 per user$q$, $q$Monthly$q$, $q$["Everything in Pro","API key access and webhooks","SAML/SSO for enterprise sign-in","Advanced customization for complex, scaled operations","Priority support options"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$When I Work is a cloud-based employee scheduling and time tracking platform built for shift-based businesses. Founded in 2010 and headquartered in Minneapolis, Minnesota, the company set out to replace paper schedules and spreadsheets with a simple, mobile-first system. Today it serves restaurants, retailers, healthcare facilities, and other hourly workforces that need to build schedules quickly, track worked hours accurately, and keep managers and staff connected wherever they are.$q$, $q$At its core, When I Work combines drag-and-drop scheduling, a GPS-enabled time clock, and built-in team messaging into a single subscription. Managers can build a week's schedule in minutes, publish it instantly to every employee's phone, and let staff handle shift swaps and open-shift requests themselves within rules the manager sets. That self-service layer is one of the platform's most consistently praised aspects among long-time users.$q$, $q$The product is organized around three paid tiers - Essentials, Pro, and Premium - priced per user per month, plus an optional time and attendance add-on. All plans start with a 14-day free trial that requires no credit card, and customers can change plans or seat counts at any time without a contract. This tiered structure lets a single-location coffee shop and a multi-state retail chain both find a fit, though pricing and feature depth scale with complexity.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$who-when-i-work-is-for$q$, $q$Who When I Work Is For$q$, 2, ARRAY[$q$When I Work is best suited to businesses that schedule hourly employees by the shift rather than salaried staff who work fixed hours. Restaurants, cafes, retail stores, gyms, salons, hotels, and other hospitality or service operations are the platform's core audience, since these industries depend on getting the right number of people on the floor at the right time.$q$, $q$The tool also fits growing multi-location operators. The Pro and Premium tiers add labor sharing across sites, forecasting tools, custom reporting, and role-based permissions, which help area or regional managers oversee several locations without losing visibility into any single one. Franchise owners and small regional chains frequently cite this multi-site view as a reason they moved off spreadsheets.$q$, $q$Small business owners scheduling for the first time will also find it approachable. The interface is simple enough that a manager with no scheduling-software background can build a working week within an afternoon, and the mobile apps mean staff can check schedules, request time off, and swap shifts without a manager fielding every text message.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Companies with mostly salaried, fixed-schedule staff - professional services firms, most software companies, or back-office teams - will not get much value from a tool purpose-built around shift rotation, availability, and hourly time tracking. A general-purpose HR or project time-tracking tool is usually a better fit for that kind of workforce.$q$, $q$Field teams that regularly work without reliable internet access should also be cautious, since the mobile app does not fully function offline; punches and schedule changes typically need a connection to sync reliably. Businesses that need deep integration with a specific existing HRIS or a highly specialized payroll workflow beyond the native integrations should confirm compatibility first, since deeper connections are generally Premium-plan or add-on features.$q$, $q$Some current users also report occasional bugs, syncing delays, and notification issues on both the web portal and mobile app, along with a learning curve around the more advanced permission and forecasting features. Organizations with zero tolerance for occasional glitches, or that need highly customized enterprise-grade workflows out of the box, may want to weigh dedicated workforce-management suites alongside When I Work before deciding.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The scheduling engine is the heart of the product: drag-and-drop shift building, shift templates, an auto-scheduler that matches shifts to availability and preferences, and open shifts that employees can claim themselves. Shift swap and drop requests route through manager approval rules automatically, cutting down the back-and-forth that usually happens over text or phone calls.$q$, $q$The built-in time clock lets employees clock in and out from their phone or a shared kiosk, with GPS location capture and geofencing that confirms staff are on-site when they punch in. Time and attendance data feeds directly into native payroll integrations with providers like Gusto, QuickBooks Online, ADP Workforce Now, and Square Payroll, reducing manual re-entry when running payroll.$q$, $q$Team communication is built in rather than bolted on, with one-to-one and group messaging, shift reminders, and announcements delivered through the same app employees already use for their schedule. Higher tiers add labor cost forecasting, custom and 24-hour callout reporting, role-based permissions for multi-location oversight, and, on the Premium plan, API access, webhooks, and SAML/SSO for larger organizations.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$the-when-i-work-experience$q$, $q$The When I Work Experience$q$, 2, ARRAY[$q$Day to day, When I Work is built around the mobile app as much as the web dashboard - most employees interact with their schedule, time clock, and messages entirely from their phone, while managers do the heavier schedule-building from a browser. The overall workflow favors speed: publishing a schedule, approving a swap, or answering a time-off request typically takes a few taps rather than a multi-step process.$q$, $q$Onboarding a single location is generally described as fast, with new managers able to import staff, set availability rules, and publish a first schedule within a day. Multi-location or Premium-tier setups involving forecasting, custom permissions, or SSO take more configuration, and larger teams should expect a longer ramp-up period as they tune the rules that govern auto-scheduling and reporting.$q$, $q$Support is available through an online help center and ticket-based customer care in English, and the company continues to ship incremental feature updates rather than major overhauls. For shift-based teams that want scheduling, time tracking, and messaging bundled into one subscription instead of three separate tools, the day-to-day experience is generally straightforward, even though some users note occasional bugs and sync delays that the product continues to work through.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
