INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$No-download browser calling$q$, $q$Meetings run entirely in the browser using WebRTC, so guests can join from a link without installing any app or creating an account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Persistent room URLs$q$, $q$Each room has a reusable link that can be shared repeatedly, making it easy to maintain one consistent meeting address for recurring calls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Screen sharing and spotlight layouts$q$, $q$Presenters can share their screen and adjust the video grid or spotlight a speaker so the right content stays in focus.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Cloud and local recording$q$, $q$Calls can be recorded to Whereby's cloud storage or saved locally, with transcription and live captions available for accessibility.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Breakout groups$q$, $q$Hosts can split larger meetings into smaller breakout sessions for discussions before bringing everyone back together.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Embedded collaboration tools$q$, $q$Built-in Miro whiteboards and real-time Google Docs collaboration let participants work together without leaving the call.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Custom branding and subdomains$q$, $q$Paid plans let businesses add their own logo, colors, and a custom subdomain so meeting links look and feel on-brand.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Whereby Embedded API and SDK$q$, $q$Developers can integrate Whereby's video calling technology directly into their own websites, apps, or platforms via API and SDK.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Security and compliance$q$, $q$End-to-end encryption for peer-to-peer calls, GDPR compliance, ISO 27001 certification, and HIPAA-configurable options support regulated use cases.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Mobile apps$q$, $q$Lightweight iOS and Android apps let participants join and host meetings from mobile devices in addition to desktop browsers.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Guests can join instantly from a browser link with no downloads or account creation required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Simple, clean interface that reviewers consistently describe as easy to learn and use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Persistent, reusable room URLs are convenient for recurring client or team meetings$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Offers a genuine free plan plus an API product for developers who want to embed video$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Solid security posture with GDPR compliance, ISO 27001 certification, and HIPAA-configurable options$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Free plan is limited to short calls and a single room, which may feel restrictive quickly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Attendee caps make it a poor fit for large webinars, town halls, or broadcast-style events$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Phone dial-in support is limited primarily to US numbers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Fewer deep enterprise admin, identity, and governance controls than larger platforms like Zoom or Teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Primarily English-language interface, which may not suit fully multilingual organizations$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Do meeting guests need to download an app or create an account to join a Whereby call?$q$, $q$No. Whereby runs in the browser using WebRTC, so guests can join a meeting by simply clicking a room link, with no software installation or account required.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Is Whereby free to use?$q$, $q$Whereby offers a free plan with one host, one room, and calls limited to a small group and short duration. Paid Pro and Business plans remove those limits and add more rooms, larger meeting capacity, and custom branding.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$What is Whereby Embedded?$q$, $q$Whereby Embedded is a separate API and SDK product that lets developers integrate Whereby's video calling technology directly into their own websites, apps, or platforms rather than using the standalone Whereby Meetings app.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$How many people can join a Whereby meeting?$q$, $q$Capacity depends on the plan, ranging from a handful of participants on the free tier up to around 200 attendees on paid Meetings plans, with additional viewer-only capacity available on higher tiers.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Is Whereby secure and compliant for sensitive conversations?$q$, $q$Whereby supports end-to-end encryption for peer-to-peer calls, is GDPR compliant, holds ISO 27001 certification, and offers HIPAA-configurable settings, making it usable for many healthcare and business compliance needs.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Client meetings for freelancers and consultants$q$, $q$A reusable, branded room link makes it simple to host recurring client calls, coaching sessions, or consultations without asking clients to install anything.$q$, $q$Freelancers, consultants, and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Lightweight team video calls$q$, $q$Small and distributed teams use Whereby for quick huddles, standups, and ad hoc video chats that don't require heavyweight scheduling or a full collaboration suite.$q$, $q$Small and remote-first teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Telehealth and virtual appointments$q$, $q$A persistent, easy-to-join room supports one-on-one virtual visits between practitioners and clients, with security and compliance features suited to sensitive conversations.$q$, $q$Telehealth providers and independent practitioners$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Embedded video in custom applications$q$, $q$Whereby Embedded lets product and engineering teams add live video calling into their own marketplace, learning platform, or SaaS product using an API and SDK.$q$, $q$Developers and product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["1 host and 1 room URL","Up to 4 attendees per meeting","Meetings limited to 30 minutes","Basic video conferencing and screen sharing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Pro$q$, $q$$10.99/month$q$, $q$Monthly (discount available on annual billing)$q$, $q$["1 host and 3 room URLs","Up to 100 attendees per meeting","No time limit on meetings","Custom branding and unlimited recording"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Business$q$, $q$$13.99/month per host (minimum 3 hosts)$q$, $q$Monthly (discount available on annual billing)$q$, $q$["Everything in Pro","Unlimited room URLs","Up to 200 attendees per meeting","Shared and flex rooms with a custom subdomain","14-day free trial available"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Whereby is a browser-based video conferencing platform built on WebRTC, letting anyone join a meeting through a simple link with no app or plugin to install. It traces its roots to appear.in, a project born inside Norwegian telecom Telenor in 2013 that pioneered peer-to-peer video calling directly in the browser. The company spun out, was acquired by Videonor, and rebranded as Whereby in 2019, before Whereby itself became part of video infrastructure provider Pexip in 2021.$q$, $q$Today Whereby operates two related products: Whereby Meetings, a consumer-facing app for scheduling and hosting persistent video rooms, and Whereby Embedded, a video calling API and SDK that lets developers bake Whereby's video technology directly into their own products. Both share the same emphasis on frictionless, no-download video built for the modern web rather than legacy desktop clients.$q$, $q$The company is headquartered in Norway and remains a relatively small, focused team compared to giants like Zoom or Microsoft Teams. Rather than chasing every enterprise collaboration feature, Whereby has stayed narrowly focused on making one-click, browser-native video calling as simple, fast, and pleasant to use as possible for small teams, freelancers, and platforms that need embedded video. Whereby has also leaned into browser compatibility across Chrome, Firefox, Safari, and Edge, and maintains lightweight iOS and Android apps for joining calls on mobile devices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$who-whereby-is-for$q$, $q$Who Whereby Is For$q$, 2, ARRAY[$q$Whereby is best suited to freelancers, consultants, coaches, and small businesses that need a professional, branded meeting room without asking clients to download software or create an account. A single persistent room URL that can be reused for every meeting is a natural fit for recurring client calls, therapy or coaching sessions, and sales demos.$q$, $q$Small and mid-sized teams that want lightweight video calling alongside chat, screen sharing, and light collaboration tools (like embedded Miro boards or Google Docs) will also find Whereby a good match, especially teams that value simplicity over a deep enterprise feature set. It also suits distributed and remote-first companies that prioritize quick, ad hoc video huddles over scheduled, agenda-heavy conferences. Telehealth providers, online tutors, and recruiters running back-to-back interviews are especially common use cases, since a single reusable link removes the friction of sending a new invite for every session.$q$, $q$Developers and product teams building their own apps, marketplaces, telehealth platforms, or online learning tools are a distinct and important audience: Whereby Embedded gives them a video calling API and SDK so they can add real-time video to their own product without building WebRTC infrastructure from scratch.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises that run frequent town halls, webinars, or trainings for hundreds or thousands of attendees should look elsewhere, since Whereby Meetings caps room capacity well below what dedicated webinar platforms support. Organizations with strict, complex IT governance needs, such as enterprise-wide SSO rollouts, granular device management, or deep integration with an existing Microsoft 365 or Google Workspace identity stack, may find Whereby's admin tooling comparatively light.$q$, $q$Teams that rely heavily on phone dial-in for international participants may also be frustrated, since Whereby's dial-in support is limited primarily to US numbers. Similarly, organizations needing a fully multilingual meeting interface for global, non-English-speaking staff should verify current language coverage before committing, since Whereby's own apps are documented primarily in English. Companies bound by regional data residency rules that require infrastructure outside Whereby's supported regions should confirm compliance details directly with the vendor before adopting it at scale.$q$, $q$Finally, businesses that want a single all-in-one suite combining video, chat, file storage, and productivity apps under one roof, in the style of Microsoft Teams or Google Meet bundled with a broader workspace, will likely find Whereby too narrowly scoped, since it focuses specifically on video calling rather than being a complete collaboration platform.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Whereby offers persistent, link-based meeting rooms with HD video, screen sharing, and a customizable grid or spotlight layout, along with host controls like locked rooms, waiting areas, and the ability to mute or remove participants. Meetings can be recorded to the cloud or locally, and both live captioning and post-call transcription are available to improve accessibility and make meetings easier to reference later.$q$, $q$Collaboration features extend the core call: breakout groups for splitting participants into smaller discussions, embedded Miro whiteboards, real-time Google Docs collaboration, in-call chat with reactions, and drag-and-drop file sharing. Paid plans add custom branding, custom subdomains, and unlimited or additional room URLs, so a business can present a consistent, professional look across every meeting link it shares.$q$, $q$For developers, Whereby Embedded exposes the same underlying video infrastructure as an API and SDK, enabling video calling to be embedded inside a website, mobile app, or SaaS product. On the security side, Whereby supports end-to-end encryption for peer-to-peer calls, is GDPR compliant and ISO 27001 certified, and can be configured to support HIPAA requirements for healthcare use cases.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$the-whereby-experience$q$, $q$The Whereby Experience$q$, 2, ARRAY[$q$The defining characteristic of using Whereby is how little friction stands between clicking a link and being on a call. There is no mandatory account creation for guests and no software to install, so joining feels closer to opening a web page than launching a conferencing app. Reviewers consistently point to this simplicity, along with a clean, modern interface, as Whereby's biggest strength relative to heavier competitors.$q$, $q$That simplicity comes with tradeoffs. Because rooms are the core unit rather than scheduled, calendar-driven meetings in the style of Zoom or Teams, teams that rely heavily on complex meeting scheduling workflows may need to adapt their habits. Attendee caps, currently up to 200 participants on the highest self-serve tier, mean Whereby is built for team and small-group meetings rather than large broadcast-style events.$q$, $q$Overall, the experience skews toward speed and ease over configurability. For its core audience, that tradeoff is the point: fewer settings to manage, less onboarding friction for guests, and a video calling tool that gets out of the way so the conversation stays the focus.$q$]::text[], 4);
