INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Cascade AI Agent$q$, $q$An agentic pane that reads your codebase, plans multi-step changes, edits multiple files, and runs terminal commands in one workflow.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Reviewable Diffs$q$, $q$Cascade stages every edit as a diff with per-step approval so changes can be reviewed, edited, or rejected before they hit disk.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Fast Inline Autocomplete$q$, $q$Predictive completion that suggests full edits and next likely actions, not just single lines, and remains unlimited on the free tier.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Model Context Protocol Support$q$, $q$Connect external tools, internal systems, and data sources directly into Cascade's context via MCP servers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Multi-Model Support$q$, $q$Switch between Claude, GPT, and Windsurf's own in-house SWE coding model depending on task and cost.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Terminal Command Execution$q$, $q$Cascade can run shell commands such as installing dependencies or running migrations as part of its plan.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$VS Code-Based Editor$q$, $q$Built on a familiar Visual Studio Code fork, keeping keybindings, themes, and much of the extension experience intact.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Enterprise Deployment Options$q$, $q$Self-hosted and air-gapped deployment options carried over from the product's Codeium enterprise roots.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Extensions and Integrations$q$, $q$Integrations with tools like Slack, Linear, Figma, and common language servers to extend the editor's workflow.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Cascade agent handles multi-file, multi-step coding tasks with reviewable diffs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Fast, unlimited autocomplete even on the free plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Flexible Model Context Protocol support for connecting external tools and data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Access to multiple frontier AI models plus an in-house coding model$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Backed by Cognition's broader Devin agent ecosystem and engineering resources$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Product has been renamed twice (Codeium to Windsurf to Devin Desktop), creating brand confusion$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Pricing structure has changed more than once, from credits to daily/weekly quotas$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Future roadmap now depends on Cognition's Devin strategy rather than a standalone Windsurf team$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Higher usage tiers (Max plan) can get expensive for heavy daily agent use$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Enterprise customers must track migration and login changes tied to the rebrand$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Is Windsurf still called Windsurf?$q$, $q$As of June 2026, Cognition rebranded the Windsurf editor as Devin Desktop. Existing Windsurf accounts, plans, and settings carried over automatically, and Legacy Windsurf Enterprise customers continue to log in via windsurf.com/enterprise.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$What happened after Cognition acquired Windsurf?$q$, $q$Cognition, the maker of the autonomous coding agent Devin, acquired Windsurf in 2025 for a reported figure around 250 million dollars, then folded the product into its Devin family, renaming it Devin Desktop in June 2026.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Does Windsurf have a free plan?$q$, $q$Yes. The free tier includes unlimited Tab-style autocomplete and inline edits, plus a limited daily and weekly quota for Cascade agent tasks.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$What AI models does Windsurf support?$q$, $q$Windsurf supports multiple frontier models, including models from Anthropic and OpenAI, alongside its own in-house SWE coding model, selectable depending on the task and plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Does Windsurf support the Model Context Protocol (MCP)?$q$, $q$Yes. Cascade natively supports MCP, letting teams connect their own external tools, servers, and data sources into the agent's context.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Multi-file refactoring$q$, $q$Use Cascade to plan and execute changes across many files at once, reviewing each staged diff before it is applied.$q$, $q$Professional software engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Rapid prototyping$q$, $q$Describe a feature in plain language and let Cascade scaffold files, install dependencies, and iterate quickly toward a working prototype.$q$, $q$Startups and indie developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Enterprise codebase modernization$q$, $q$Apply agent-assisted changes across large, self-hosted codebases while keeping human review and approval in the loop.$q$, $q$Enterprise engineering teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Learning AI-assisted development$q$, $q$Explore how an AI agent reasons about code, proposes edits, and runs commands, with every step visible for learning purposes.$q$, $q$Students and developers new to AI coding tools$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Free$q$, $q$$0$q$, $q$N/A$q$, $q$["Unlimited Tab-style autocomplete and inline edits","Limited daily and weekly Cascade agent quota","Access to the core editor"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Pro$q$, $q$$20$q$, $q$per month$q$, $q$["Higher daily and weekly Cascade quotas","Access to premium models including Claude and GPT models","Access to Windsurf's in-house SWE coding model"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Teams$q$, $q$$40 per user$q$, $q$per month$q$, $q$["All Pro features","Centralized billing and admin dashboard","Usage analytics","Knowledge Base integration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$custom$q$, $q$["Self-hosted or air-gapped deployment options","SSO and enterprise admin controls","Dedicated support and onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Windsurf is an AI-native code editor built on a Visual Studio Code fork by the team formerly known as Codeium, best known for its Cascade agent: an AI pane that can read an entire codebase, plan multi-step changes, edit multiple files at once, run terminal commands, and call external tools through the Model Context Protocol, all while staging its work as a reviewable diff before anything is written to disk. Alongside Cascade, the editor ships fast inline autocomplete that predicts entire edits rather than single lines, plus support for several frontier models including Anthropic's Claude family, OpenAI's GPT models, and Windsurf's own in-house SWE coding model.$q$, $q$The company was founded in 2021 in Mountain View, California, initially as Codeium, an AI-assisted coding startup that built autocomplete and chat tools for existing editors before launching its own standalone IDE under the Windsurf name. In 2025, Windsurf was acquired by Cognition, the company behind the autonomous coding agent Devin, in a deal reported at roughly 250 million dollars. In June 2026, Cognition folded the product into its Devin lineup, renaming it Devin Desktop as part of a broader push to unify its supervised (desktop) and autonomous (cloud) coding agents under one brand; existing Windsurf accounts, plans, and settings carried over automatically.$q$, $q$For a directory entry, Windsurf is best understood as the editor's enduring identity among developers even after the rename: it is the product people search for, recommend, and compare against Cursor, GitHub Copilot, and other AI-assisted IDEs, and its documentation, extensions, and enterprise login still live at windsurf.com/enterprise and related subdomains.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$who-windsurf-is-for$q$, $q$Who Windsurf Is For$q$, 2, ARRAY[$q$Windsurf suits professional developers and teams who want an AI agent embedded directly in their editor rather than bolted on as a chat sidebar. It works well for engineers tackling multi-file refactors, migrations, or feature builds where an agent that can plan, edit, run commands, and iterate saves real time, especially when paired with the diff-review workflow that keeps a human in the loop before code lands.$q$, $q$Startups and small teams that want to move fast benefit from the generous free tier for autocomplete and light agent use, then scale into a paid plan as usage grows. Engineering teams that already lean on Model Context Protocol servers, internal tooling, or a mix of AI models will appreciate Cascade's flexibility in connecting external context sources and switching between Claude, GPT, and Windsurf's own models depending on the task.$q$, $q$Enterprises with existing Codeium or Windsurf deployments, including those using self-hosted or air-gapped setups, are a natural fit given the product's roots in enterprise-focused code assistance, and its continuity of plans and licensing through the Cognition acquisition and the Devin Desktop rename.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Developers who want a single, stable brand and interface that will not change again soon should be cautious: Windsurf has been renamed once already (from Codeium) and again in 2026 (to Devin Desktop), and its pricing model has also shifted more than once, from credit-based billing to daily and weekly quotas. Anyone allergic to that kind of platform churn may prefer a tool with a longer track record of naming and pricing stability.$q$, $q$Organizations with strict requirements around vendor independence or long-term roadmap certainty should also weigh the fact that Windsurf now operates as a subsidiary brand inside Cognition's Devin product family rather than as a standalone company, which means its future direction is tied to Cognition's broader agent strategy rather than a dedicated Windsurf roadmap.$q$, $q$Developers who prefer minimal, manual-first editors without an AI agent constantly proposing changes, or who need deep parity with the full Visual Studio Code extension marketplace, may find the agent-centric workflow and editor fork model more friction than benefit compared with using a thin AI plugin on top of standard VS Code.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of the product is Cascade, the agentic pane that turns natural-language requests into concrete code changes: it reads the project, forms a plan, edits the relevant files, and can run shell commands such as installing dependencies or running migrations, surfacing every tool call, command, and file change as an inspectable step in the conversation.$q$, $q$Autocomplete is handled separately and is fast enough to feel like traditional IDE completion while still predicting larger, multi-line edits and next likely actions across a file, and it remains available even on the free tier without the quota limits that apply to agent tasks.$q$, $q$Model Context Protocol support lets teams plug in their own external tools and data sources, so Cascade can pull context from internal systems, documentation, or other services rather than being limited to what is already open in the editor, and the editor supports multiple underlying models so teams can choose between third-party frontier models and Windsurf's own coding-focused model depending on cost and task complexity.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('758d739b-574e-4253-96df-178cefd5f067', $q$the-windsurf-experience$q$, $q$The Windsurf Experience$q$, 2, ARRAY[$q$Using Windsurf feels like working inside a familiar VS Code-style editor with an AI collaborator built into the core workflow rather than added as an afterthought: prompts, diffs, and terminal output sit alongside the file tree and editor panes, and changes are proposed as staged diffs that a developer approves, rejects, or edits before they are committed to the codebase.$q$, $q$The day-to-day rhythm centers on describing a task in plain language, watching Cascade break it into steps, and reviewing each file change or command as it happens, which keeps the pace of AI-assisted development fast without removing the developer from the decision-making loop.$q$, $q$Following the Cognition acquisition and the mid-2026 rename to Devin Desktop, the underlying day-to-day experience for existing users has largely continued as before, with the same interface, keybindings, and plans carrying over; the most visible change for long-time Windsurf users has been the branding shift and the product's positioning as one part of a larger family of Devin coding agents rather than a standalone editor.$q$]::text[], 4);
