INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Multi-currency account$q$, $q$Hold and manage balances in dozens of currencies from a single account instead of opening separate foreign accounts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Local account details$q$, $q$Get local bank details, such as IBAN, routing number, or sort code, in several major currencies to receive payments like a local business.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Batch payments$q$, $q$Upload a file to pay up to 1,000 recipients in one go, useful for payroll, contractor payouts, or supplier payments.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Wise Business card$q$, $q$Issue multi-currency debit cards to employees with individual spending limits and real-time expense tracking.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Invoicing and payment links$q$, $q$Create invoices and shareable payment links so international customers can pay directly into the account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Mid-market exchange rates$q$, $q$Convert currencies at the real mid-market rate plus a small, disclosed fee instead of a hidden bank markup.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Accounting software integrations$q$, $q$Sync transactions automatically with platforms such as Xero and QuickBooks to cut down manual bookkeeping.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$API access$q$, $q$Automate payments, payouts, and reconciliation programmatically through Wise's business API.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Interest on balances$q$, $q$Earn variable interest on eligible currency balances held in the account.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Web and mobile access$q$, $q$Manage the account from a web dashboard or the iOS and Android apps with real-time balance visibility.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Mid-market exchange rates with transparent, disclosed fees instead of hidden bank markups$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$No monthly account fee; pay-as-you-go pricing based on actual usage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Local receiving account details in multiple currencies make it easy for international clients to pay without wire fees$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Batch payments and API access streamline payouts for teams handling contractors or suppliers at scale$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Fast international transfers, with most arriving well within a day$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$One-time setup fee applies even for very small or occasional international senders$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$No lending, overdraft, or credit products, so it cannot replace a full-service business bank$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$No physical branches or cash deposit facilities$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$ATM withdrawals beyond the free monthly allowance and e-wallet top-ups carry additional fees$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Customer support is primarily digital, via chat and help center, without phone-first banking for urgent issues$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Does Wise Business charge a monthly fee?$q$, $q$No, Wise Business has no recurring monthly subscription. Customers pay a one-time setup fee and then per-transaction fees based on usage, such as currency conversion, transfers, and card spending.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Which currencies can I hold in a Wise Business account?$q$, $q$Wise Business supports holding and converting dozens of currencies, with local account details available in several major currencies, such as USD, EUR, GBP, and AUD, so businesses can receive payments like a local company.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Can I pay multiple people at once with Wise Business?$q$, $q$Yes, batch payments let businesses upload a file and pay up to 1,000 recipients in a single transaction, which is useful for payroll, contractor payouts, or supplier payments.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Does Wise Business integrate with accounting software?$q$, $q$Yes, Wise Business connects natively with platforms such as Xero and QuickBooks, automatically syncing transactions so businesses do not have to enter multi-currency transfers manually.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Is Wise Business regulated and safe for holding company funds?$q$, $q$Wise operates as a regulated financial institution, or through regulated partners, in the markets it serves and safeguards customer funds separately from its own operating funds, though it is not a traditional bank and works differently from bank deposit protections.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Paying international contractors and remote teams$q$, $q$A company with remote employees or freelancers in different countries uses batch payments to pay everyone in their local currency from a single upload, cutting down on the time and fees involved in individual wire transfers.$q$, $q$Remote-first companies and agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Collecting payments from overseas customers$q$, $q$An e-commerce or SaaS business uses local account details in USD, EUR, and GBP so international customers can pay via local bank transfer, avoiding the wire fees and delays of cross-border payments.$q$, $q$E-commerce sellers and SaaS companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Managing multi-currency supplier payments$q$, $q$An importer converts revenue into a supplier's local currency at the mid-market rate and sends payment directly, reducing the margin lost to a traditional bank's exchange-rate markup.$q$, $q$Importers and exporters$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Controlling team expenses across borders$q$, $q$A growing startup issues Wise Business cards to employees traveling or spending internationally, setting individual limits and tracking spend in real time from the dashboard.$q$, $q$Startups and scale-ups with distributed teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$Pay As You Go$q$, $q$$31 one-time setup fee$q$, $q$One-time setup plus per-transaction fees$q$, $q$["No monthly subscription fee","Currency conversion from around 0.33% at the mid-market rate","Local receiving account details in multiple currencies","Batch payments and invoicing tools included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$High-Volume$q$, $q$Custom reduced rates$q$, $q$Per-transaction, with volume-based discounts$q$, $q$["Available to businesses converting large monthly volumes","Lower FX conversion fees than the standard tier","Same core account features as Pay As You Go","Support suited to higher-volume payment needs"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Wise Business is the business account product from Wise (formerly TransferWise), the UK-founded fintech that pioneered sending international transfers at the mid-market exchange rate for consumers before extending the same model to companies. Founded in 2011 in London by Kristo Käärmann and Taavet Hinrikus, the company rebranded from TransferWise to Wise in 2021 and went public that same year via a direct listing on the London Stock Exchange, and now operates in the vast majority of countries worldwide, with Wise Business built specifically for companies that send, receive, hold, or convert money in multiple currencies.$q$, $q$At its core, Wise Business is a multi-currency account: businesses can hold balances in dozens of currencies, receive local account details, such as routing numbers, IBANs, and sort codes, in several major currencies, and convert between them using the mid-market exchange rate plus a small, disclosed fee rather than the wider spreads typical of traditional banks. There is no monthly subscription for the core account; instead, customers pay a one-time setup fee once and then per-transaction fees tied to how much they actually send, convert, or withdraw.$q$, $q$The product bundles currency conversion, payments, card issuing, batch payouts, invoicing, and accounting-software integrations into a single web dashboard and mobile app, positioning itself less as a full replacement for a traditional business bank and more as the international payments and multi-currency treasury layer that sits alongside, or in some cases instead of, a local business bank account for companies with cross-border operations.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$who-wise-business-is-for$q$, $q$Who Wise Business Is For$q$, 2, ARRAY[$q$Wise Business is built for freelancers, sole traders, and small-to-medium businesses that regularly send, receive, or hold money across borders, from e-commerce sellers paying overseas suppliers to marketing agencies invoicing clients in the US, UK, or EU.$q$, $q$It is also a natural fit for startups, agencies, and remote-first companies that pay contractors or distributed teams in multiple countries, since batch payments let a business upload a spreadsheet and pay hundreds of people in one go rather than initiating each transfer individually.$q$, $q$Marketplaces, importers and exporters, and consultancies that want local receiving details in currencies such as USD, EUR, GBP, or AUD, so they look like a local business to their counterparties, are a strong match, as are any company looking for a lower-cost, more transparent alternative to their bank's wire fees and hidden exchange-rate markups.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Companies that need traditional lending products, such as business loans, overdrafts, credit lines, or merchant cash advances, will not find them here, since Wise does not offer credit or financing.$q$, $q$Businesses that handle significant physical cash, need in-branch banking, or require sophisticated treasury features like cash pooling, sweeping, or multi-entity consolidation may find Wise's toolset too lightweight for their operations.$q$, $q$Larger enterprises that need a dedicated relationship manager, bespoke banking terms, or extensive integration with legacy ERP systems, and companies operating in higher-risk categories Wise does not support, will typically be better served by a conventional commercial bank or a specialized banking-as-a-service provider built for their industry.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$The core of Wise Business is its multi-currency balance, letting companies hold and convert dozens of currencies in one account and get local account details, routing numbers, IBANs, sort codes, in several major currencies, so clients abroad can pay as if paying a local business.$q$, $q$Payment tools include batch payments for paying up to 1,000 recipients in a single upload, invoicing and shareable payment links for collecting customer payments, and Wise multi-currency cards for team spending, with admin controls for setting individual spending limits and permissions across a business's team members.$q$, $q$For developers and finance teams, Wise offers a public API for automating payments, payouts, and reconciliation at scale, alongside native integrations with accounting platforms such as Xero and QuickBooks that automatically sync transactions into the right ledgers and currencies.$q$, $q$Balances in certain currencies can also earn variable interest, and all transfers run on the mid-market exchange rate with a disclosed percentage fee rather than a bank's typical spread, giving finance teams a clearer picture of the true cost of moving money internationally.$q$, $q$Wise is a regulated financial institution, or operates through regulated partners, in the jurisdictions it serves, and safeguards customer funds separately from its own operating funds rather than lending them out, details that matter for finance teams evaluating a non-bank provider for handling company funds.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', $q$the-wise-business-experience$q$, $q$The Wise Business Experience$q$, 2, ARRAY[$q$Signing up is done entirely online: a business submits company and ownership details, completes identity and compliance verification, and can typically start using the account within a few days once approved, without needing to visit a branch or meet with a banker.$q$, $q$Day-to-day, the web dashboard and mobile apps for iOS and Android give a real-time view of balances across currencies, transaction history, team spending, and integrations, with transfers initiated in a few clicks and most international payments arriving in well under a day.$q$, $q$Fee transparency is a consistent theme throughout the product, costs are shown upfront before a transfer is confirmed, and customer support is available via in-app chat and help center articles rather than phone-first banking, which suits digitally-native teams but may feel less personal than a traditional business banking relationship.$q$, $q$There is no cheque or cash deposit facility and no physical branch network, so businesses that occasionally need to handle cash will need a separate banking relationship for that purpose, but for a company whose finances are already digital, the experience feels closer to a modern SaaS product than a legacy bank portal.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3eb87668-42e1-459d-9212-aea403d70de9', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Product & Catalog Management$q$, $q$Manage physical goods, digital downloads, and variable products through the native WordPress block editor with categories, attributes, and variations.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Cart & Checkout Blocks$q$, $q$Customizable, native checkout and cart blocks that can be styled and rearranged to match any WordPress theme.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$WooPayments$q$, $q$Built-in payment processing alongside support for third-party gateways such as Stripe, PayPal, and Square.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Shipping Tools$q$, $q$Shipping zones, live carrier rates, and label printing to handle domestic and international fulfillment.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Tax Automation$q$, $q$Automated tax calculation across regions to reduce manual rate configuration for merchants.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Subscriptions & Memberships$q$, $q$Official extensions add recurring billing, membership content gating, and appointment or rental bookings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Extensions Marketplace$q$, $q$A large catalog of official and third-party extensions for marketing, shipping, accounting, and more.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Mobile App$q$, $q$iOS and Android apps for tracking orders, managing products, and viewing store stats on the go.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$REST API$q$, $q$A documented REST API that supports headless storefronts and custom integrations with other systems.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Store Analytics$q$, $q$Built-in analytics dashboard for tracking sales, orders, and customer activity over time.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Free, open-source core with no mandatory monthly platform fee or revenue share$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Full ownership of store data, code, and hosting environment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Deep customization through WordPress themes, hooks, and a large extension ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Scales from a simple shop to complex subscription and B2B catalogs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Backed by a large WordPress developer community and extension marketplace$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Requires self-managed hosting, security, and plugin or theme updates$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Total cost can add up once hosting, extensions, and premium themes are combined$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Performance depends heavily on hosting quality and plugin compatibility$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Steeper learning curve than fully hosted platforms for non-technical users$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Support quality varies across third-party extensions and themes$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Is WooCommerce really free?$q$, $q$The core WooCommerce plugin is free and open source, but most stores also pay for hosting, a domain, and often premium themes or extensions, so total cost varies by setup.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Do I need to know how to code to use WooCommerce?$q$, $q$No coding is required for a basic store setup, but customizing design or adding advanced functionality typically benefits from developer help.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$What payment gateways does WooCommerce support?$q$, $q$WooCommerce supports its own WooPayments processor as well as third-party gateways including Stripe, PayPal, Square, and many regional options.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Can WooCommerce handle large or high-traffic stores?$q$, $q$Yes, with appropriate hosting, caching, and performance optimization, WooCommerce can support large catalogs and high traffic, though this requires more setup than a fully hosted platform.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$How is WooCommerce different from Shopify?$q$, $q$WooCommerce is a self-hosted, open-source plugin that runs on your own WordPress site with no revenue share, while Shopify is a fully hosted SaaS platform that manages infrastructure for you.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Content-to-Commerce Blogs$q$, $q$Bloggers and content creators add a shop or digital downloads alongside their existing WordPress content without switching platforms.$q$, $q$Bloggers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Small Business Retail Stores$q$, $q$Independent retailers run a self-hosted online store with full control over branding, data, and payment processing.$q$, $q$Small and medium retail businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Subscription & Membership Businesses$q$, $q$Brands sell recurring products or gated content using subscription and membership extensions built on WooCommerce.$q$, $q$Subscription and membership businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Agency-Built Custom Storefronts$q$, $q$Developers and agencies use WooCommerce's open codebase and REST API to build bespoke or headless storefronts for clients.$q$, $q$Developers and digital agencies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$WooCommerce Core$q$, $q$Free$q$, $q$N/A$q$, $q$["Open-source, self-hosted plugin","Unlimited products","No revenue share on sales","Full customization via themes and hooks"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$Premium Extensions$q$, $q$$29-$299/year per extension$q$, $q$Annual$q$, $q$["Subscriptions, bookings, and memberships add-ons","Advanced shipping and marketing tools","Official support for the extension"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$WooPayments$q$, $q$Transaction-based fees (roughly 2.5%-2.9% + 30 cents per transaction)$q$, $q$Per transaction$q$, $q$["Integrated card and digital wallet payments","No separate monthly fee","Multi-currency support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$WordPress.com Commerce (hosted)$q$, $q$From $45/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Fully hosted WooCommerce store","0% WooPayments transaction fees","Free domain for one year","Access to premium and store themes"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$WooCommerce is a free, open-source ecommerce plugin for WordPress that turns any WordPress website into a fully functional online store. It launched in 2011, built by the WooThemes team of Mark Forrester, Adii Pienaar, and Magnus Jepson, and was acquired by Automattic, the company behind WordPress.com and Jetpack, in 2015. It was later rebranded simply as Woo.$q$, $q$Because it is released under the GPL and distributed through WordPress.org, WooCommerce carries no licensing fee, no mandatory monthly subscription, and no revenue share on sales. Store owners install it on self-hosted WordPress, keep full ownership of their data, and choose their own hosting, payment processors, and themes rather than being locked into a single vendor's infrastructure.$q$, $q$With millions of active installations, WooCommerce is one of the most widely used ecommerce platforms on the web, powering everything from small hobby shops to large B2B catalogs. Its block-based product editor, native checkout blocks, and growing extensions marketplace let merchants add payments, shipping, subscriptions, bookings, and marketing tools as a store grows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$who-woocommerce-is-for$q$, $q$Who WooCommerce Is For$q$, 2, ARRAY[$q$WooCommerce suits anyone already running, or planning to run, a WordPress site who wants to add a store without switching platforms. Bloggers, publishers, and content creators can sell physical products, digital downloads, or memberships alongside their existing content, blending commerce into a site they already control.$q$, $q$It's a strong fit for small and medium businesses that want to avoid platform transaction fees and retain full control over design, data, and hosting. Agencies and freelance developers also favor WooCommerce because its open codebase, action hooks, and REST API make heavily customized or white-labeled storefronts straightforward to build.$q$, $q$Merchants with unique product types, such as rentals, appointments, subscriptions, or wholesale and B2B catalogs, benefit from the deep extension ecosystem that lets them assemble a store tailored to a specific business model rather than working within a fixed set of platform features.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Non-technical users who want a fully managed, zero-maintenance store bundled into one predictable subscription may find a closed SaaS platform like Shopify a simpler starting point, since WooCommerce requires assembling hosting, security, and updates yourself, or paying someone else to do it.$q$, $q$Merchants who dislike managing a WordPress site, including plugin updates, theme compatibility, and occasional conflicts between extensions, should be cautious. WooCommerce's flexibility comes with more moving parts to maintain compared to a closed, all-in-one platform where the vendor handles infrastructure.$q$, $q$Very high-traffic or complex enterprise catalogs can outgrow a standard WordPress and WooCommerce stack without meaningful performance engineering, caching, and dedicated hosting, so businesses expecting instant, out-of-the-box enterprise-grade scaling may prefer a platform built primarily around scale from day one.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, WooCommerce provides product and inventory management through the WordPress block editor, flexible cart and checkout blocks, and support for physical goods, digital downloads, and variable products, all customizable through standard WordPress themes.$q$, $q$Built-in and extension-based tools cover payments through WooPayments and gateways like Stripe, PayPal, and Square, shipping label printing with live carrier rates, automated tax calculation, and marketing features such as coupons, abandoned cart recovery, and email marketing integrations.$q$, $q$Official extensions add subscriptions, bookings, and memberships, while the WooCommerce mobile app lets store owners track orders, manage products, and view analytics on iOS and Android. A REST API also supports headless storefronts and custom integrations for developers.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fe08bff8-895b-4ba9-9fcd-09e3e773bb57', $q$the-woocommerce-experience$q$, $q$The WooCommerce Experience$q$, 2, ARRAY[$q$Getting started typically means installing WordPress, adding the WooCommerce plugin, and running its setup wizard to configure store details, payments, shipping, and tax, a process that's approachable for existing WordPress users but involves more upfront configuration than a fully hosted competitor.$q$, $q$Day-to-day, store owners manage everything from the familiar WordPress dashboard, with a large ecosystem of themes, extensions, and third-party developers available to fill gaps. The tradeoff is that quality and support vary by extension, and larger stores often need a developer for performance tuning or custom features.$q$, $q$Community support is extensive, spanning official documentation, the WooCommerce.com marketplace, community forums, and a large pool of WordPress developers and agencies, which keeps help accessible even though there is no single dedicated account manager built into every plan the way there might be on a closed SaaS platform.$q$]::text[], 4);
