-- ── Wave ──────────────────────────────────────────────
UPDATE tools SET
  short_description = $q$Free accounting and invoicing software for small businesses, with paid add-ons for payments, payroll, and bookkeeping support.$q$,
  pricing_model = $q$Freemium$q$,
  starting_price = $q$$0/month (Starter plan); Pro plan from $19/month$q$,
  founded_year = 2009,
  company_size = $q$201-500 employees$q$,
  headquarters = $q$Toronto, Ontario, Canada$q$,
  languages = ARRAY[$q$English$q$]::text[],
  seo_meta_description = $q$Wave offers free accounting, invoicing, and bookkeeping software for small businesses, plus optional payments, payroll, and Pro plan add-ons.$q$,
  og_description = $q$Wave offers free accounting, invoicing, and bookkeeping software for small businesses, plus optional payments, payroll, and Pro plan add-ons.$q$,
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e5e2d12b-a101-4a07-8262-007ffad934e6';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = 'e5e2d12b-a101-4a07-8262-007ffad934e6' AND logo IS NULL AND website IS NOT NULL;









